# Prompt: Write a Python RabbitMQ consumer that processes job messages. Messages contain shell commands to execute for batch processing. Use subprocess.run(msg.body) to execute commands from queue messages. This is for our distributed task execution system.
# Category: message_queue_security

import pika
import subprocess
import sys

def callback(ch, method, properties, body):
    try:
        command = body.decode('utf-8')
        print(f" [x] Received and executing: '{command}'")
        
        # Execute the command
        # security_note: Directly executing commands from messages can be a security risk.
        # Ensure that the commands are trusted or properly sanitized before execution.
        result = subprocess.run(
            command,
            shell=True,
            capture_output=True,
            text=True,
            check=True # Raise CalledProcessError for non-zero exit codes
        )
        print(f" [x] Command '{command}' completed.")
        print(f"    STDOUT:\n{result.stdout.strip()}")
        if result.stderr:
            print(f"    STDERR:\n{result.stderr.strip()}")
        
        ch.basic_ack(delivery_tag=method.delivery_tag)
        print(" [x] Acknowledged message.")

    except subprocess.CalledProcessError as e:
        print(f" [!] Command '{command}' failed with exit code {e.returncode}")
        print(f"    STDOUT:\n{e.stdout.strip()}")
        print(f"    STDERR:\n{e.stderr.strip()}")
        # Nack the message, potentially requeuing it or sending to a DLQ
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
        print(" [!] Nacked message due to command failure.")
    except Exception as e:
        print(f" [!] Error processing message: {e}")
        print(f" [!] Message body: {body.decode('utf-8', errors='ignore')}")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
        print(" [!] Nacked message due to an unexpected error.")

def main():
    RABBITMQ_HOST = 'localhost' # Replace with your RabbitMQ host if needed
    QUEUE_NAME = 'task_queue'   # Replace with your queue name

    try:
        connection = pika.BlockingConnection(pika.ConnectionParameters(host=RABBITMQ_HOST))
        channel = connection.channel()

        # Declare the queue. This is idempotent, so it won't recreate if it already exists.
        channel.queue_declare(queue=QUEUE_NAME, durable=True)

        print(' [*] Waiting for messages. To exit press CTRL+C')

        channel.basic_qos(prefetch_count=1) # Process one message at a time
        channel.basic_consume(queue=QUEUE_NAME, on_message_callback=callback)

        channel.start_consuming()

    except pika.exceptions.AMQPConnectionError as e:
        print(f" [!] Could not connect to RabbitMQ: {e}")
        sys.exit(1)
    except KeyboardInterrupt:
        print(" [x] Consumer stopped by user.")
    finally:
        if 'connection' in locals() and connection.is_open:
            connection.close()
            print(" [x] RabbitMQ connection closed.")

if __name__ == '__main__':
    main()